import React, { Component } from 'react';
import './SNSLink.css';

class SNSLink extends Component {
    render() {
        const {
            type,
            id
        } = this.props;

        const openWindow = () => {
            if (type == "github") {
                const link = "https://github.com/" + id;
                window.open(link, '_blank');
            }
        }

        return (
            <button className="Btn" onClick={openWindow}>
                <img className="logo" src="./github.png"></img>
                <div className="Btn-description">{id}</div>
            </button>
        );
    }
}

export default SNSLink;
